class Query(ObjectType):
    product = Field(ProductType, id=Argument(ID), sku=Argument(String))
    products = List(
        ProductType,
        category_id=Argument(ID),
        category_slug=Argument(String),
        in_stock=Argument(Boolean),
        min_price=Argument(Float),
        max_price=Argument(Float),
        search=Argument(String),
        limit=Argument(Int),
        offset=Argument(Int),
    )

    category = Field(CategoryType, id=Argument(ID), slug=Argument(String))
    categories = List(CategoryType)

    review = Field(ReviewType, id=Argument(ID))
    reviews = List(
        ReviewType,
        product_id=Argument(ID),
        user_id=Argument(ID),
        min_rating=Argument(Int),
        limit=Argument(Int),
        offset=Argument(Int),
    )

    def resolve_product(root, info, id=None, sku=None):
        if id is None and sku is None:
            raise GraphQLError("Provide either 'id' or 'sku' for product.")
        if id is not None:
            return DATA["products_by_id"].get(str(id))
        return DATA["products_by_sku"].get(str(sku))

    def resolve_products(
        root,
        info,
        category_id=None,
        category_slug=None,
        in_stock=None,
        min_price=None,
        max_price=None,
        search=None,
        limit=None,
        offset=None,
    ):
        items = list(DATA.get("products", []))

        if category_slug is not None:
            cat = DATA["categories_by_slug"].get(str(category_slug))
            if not cat:
                items = []
            else:
                category_id = cat["id"]

        if category_id is not None:
            items = [p for p in items if str(p["category_id"]) == str(category_id)]

        if in_stock is not None:
            items = [p for p in items if bool(p["in_stock"]) == bool(in_stock)]

        if min_price is not None:
            items = [p for p in items if float(p["price"]) >= float(min_price)]
        if max_price is not None:
            items = [p for p in items if float(p["price"]) <= float(max_price)]

        if search:
            s = str(search).strip().lower()
            if s:
                items = [
                    p
                    for p in items
                    if s in str(p["name"]).lower()
                    or s in str(p.get("description") or "").lower()
                    or s in str(p["sku"]).lower()
                ]

        offset = int(offset or 0)
        if limit is None:
            return items[offset:]
        return items[offset : offset + int(limit)]

