def create_app():
    app = Flask(__name__)

    @app.get("/healthz")
    def healthz():
        return jsonify({"ok": True})

    @app.post("/graphql")
    def graphql_post():
        payload = request.get_json(silent=True) or {}
        query = payload.get("query")
        variables = payload.get("variables")
        operation_name = payload.get("operationName")
        if not query:
            return jsonify({"errors": [{"message": "Missing 'query' in request body."}]}), 400

        result = schema.execute(
            query,
            variable_values=variables,
            operation_name=operation_name,
            context_value={"request": request},
        )
        response = {}
        if result.errors:
            response["errors"] = [{"message": str(e)} for e in result.errors]
        if result.data is not None:
            response["data"] = result.data
        status = 200 if not result.errors else 400
        return jsonify(response), status

    @app.get("/graphql")
    def graphql_get():
        query = request.args.get("query")
        variables = request.args.get("variables")
        operation_name = request.args.get("operationName")
        if not query:
            return jsonify(
                {
                    "message": "GraphQL endpoint. Send a POST with JSON body: {query, variables, operationName}. Introspection is enabled."
                }
            )

        import json

